const input = $input.first().json;
const action = input.action || '';

const SUPABASE_URL = '{{SUPABASE_URL}}';
const SUPABASE_KEY = '{{SUPABASE_SERVICE_KEY}}';
const pgHeaders = { 'apikey': SUPABASE_KEY, 'Authorization': 'Bearer ' + SUPABASE_KEY };

const creds = await helpers.httpRequest({
  method: 'GET',
  url: SUPABASE_URL + '/rest/v1/template_credentials?template_id=eq.genesis-destatis&cred_key=eq.genesis_token&select=cred_value',
  headers: pgHeaders
});
if (!creds || creds.length === 0 || !creds[0].cred_value) {
  return [{ json: { error: 'GENESIS-Token nicht konfiguriert. Kostenlosen Token holen: https://www-genesis.destatis.de/datenbank/online -> Mein Profil -> API-Zugang. Dann mit add_credential einrichten.' } }];
}
const token = creds[0].cred_value;
const BASE = 'https://www-genesis.destatis.de/genesisWS/rest/2020/';

async function genesisCall(path, params) {
  const body = new URLSearchParams();
  for (const [k, v] of Object.entries(params || {})) {
    if (v !== undefined && v !== null && v !== '') body.append(k, String(v));
  }
  let res;
  try {
    res = await helpers.httpRequest({
      method: 'POST',
      url: BASE + path,
      headers: {
        'username': token,
        'Content-Type': 'application/x-www-form-urlencoded; charset=UTF-8',
        'Accept': 'application/json'
      },
      body: body.toString()
    });
  } catch (e) {
    throw new Error('GENESIS HTTP-Fehler (' + path + '): ' + e.message);
  }
  if (res && typeof res.Code === 'number' && res.Code !== 0 && !res.Status) {
    throw new Error('GENESIS error ' + res.Code + ': ' + (res.Content || ''));
  }
  if (res && res.Status && res.Status.Type === 'ERROR') {
    throw new Error('GENESIS error ' + res.Status.Code + ': ' + res.Status.Content);
  }
  return res;
}

function trunc(s, n) {
  if (!s) return '';
  if (s.length <= n) return s;
  return s.substring(0, n) + '\n\n... (gekuerzt bei ' + n + ' Zeichen, total ' + s.length + ' Zeichen).';
}

function fmtList(items, max) {
  const out = [];
  let count = 0;
  for (const it of (items || [])) {
    out.push('- [' + it.Code + '] ' + (it.Content || '').replace(/\n/g, ' ') + (it.Time ? ' (' + it.Time + ')' : ''));
    count++;
    if (count >= max) break;
  }
  return out.join('\n');
}

const lang = (input.language || 'de').toLowerCase();

try {
  if (action === 'genesis_search') {
    if (!input.term) return [{ json: { error: 'Parameter "term" ist erforderlich.' } }];
    const data = await genesisCall('find/find', {
      term: input.term,
      category: input.category || 'all',
      pagelength: input.pagelength || '20',
      language: lang
    });
    let result = 'Suche "' + input.term + '" (' + lang + '):\n\n';
    let total = 0;
    if (data.Tables && data.Tables.length) { result += 'Tables:\n' + fmtList(data.Tables, 20) + '\n\n'; total += data.Tables.length; }
    if (data.Statistics && data.Statistics.length) { result += 'Statistics:\n' + fmtList(data.Statistics, 20) + '\n\n'; total += data.Statistics.length; }
    if (data.Cubes && data.Cubes.length) { result += 'Cubes:\n' + fmtList(data.Cubes, 20) + '\n\n'; total += data.Cubes.length; }
    if (data.Timeseries && data.Timeseries.length) { result += 'Timeseries:\n' + fmtList(data.Timeseries, 20) + '\n\n'; total += data.Timeseries.length; }
    if (data.Variables && data.Variables.length) { result += 'Variables:\n' + fmtList(data.Variables, 20) + '\n\n'; total += data.Variables.length; }
    if (total === 0) {
      result += 'Keine Treffer.';
      if (lang === 'de') result += ' Hinweis: Bei deutschen Suchbegriffen liefert GENESIS oft leere Resultate. Versuch language=en mit englischem Wort (z.B. "migration" statt "Wanderung").';
    }
    return [{ json: { result: trunc(result, 5000) } }];
  }

  if (action === 'genesis_list_tables') {
    if (!input.selection) return [{ json: { error: 'Parameter "selection" ist erforderlich (z.B. "12711*" oder "61*").' } }];
    const data = await genesisCall('catalogue/tables', { selection: input.selection, pagelength: input.pagelength || '20', language: lang });
    const list = data.List || [];
    const result = 'Tabellen fuer selection="' + input.selection + '" (' + list.length + '):\n\n' + fmtList(list, 50);
    return [{ json: { result: trunc(result, 5000) } }];
  }

  if (action === 'genesis_list_statistics') {
    const data = await genesisCall('catalogue/statistics', { selection: input.selection || '', pagelength: input.pagelength || '50', language: lang });
    const list = data.List || [];
    const result = 'Statistiken (' + list.length + ')' + (input.selection ? ' fuer "' + input.selection + '"' : '') + ':\n\n' + fmtList(list, 50);
    return [{ json: { result: trunc(result, 5000) } }];
  }

  if (action === 'genesis_list_variables') {
    const data = await genesisCall('catalogue/variables', { selection: input.selection || '', type: input.type || 'Alle', pagelength: input.pagelength || '30', language: lang });
    const list = data.List || [];
    const result = 'Variablen (' + list.length + '):\n\n' + fmtList(list, 50);
    return [{ json: { result: trunc(result, 5000) } }];
  }

  if (action === 'genesis_list_values') {
    if (!input.name) return [{ json: { error: 'Parameter "name" ist erforderlich (Variablen-Code, z.B. "JAHR", "NAT", "GES", "DLAND").' } }];
    const data = await genesisCall('catalogue/values2variable', { name: input.name, pagelength: input.pagelength || '30', language: lang });
    const list = data.List || [];
    const result = 'Werte fuer Variable "' + input.name + '" (' + list.length + '):\n\n' + fmtList(list, 50);
    return [{ json: { result: trunc(result, 5000) } }];
  }

  if (action === 'genesis_table_metadata') {
    if (!input.name) return [{ json: { error: 'Parameter "name" ist erforderlich (Tabellen-Code, z.B. "12711-0001").' } }];
    const data = await genesisCall('metadata/table', { name: input.name, language: lang });
    const obj = data.Object || {};
    let result = 'Metadaten Tabelle ' + (obj.Code || input.name) + ':\n\n';
    result += 'Titel: ' + (obj.Content || '-') + '\n';
    if (obj.Time) result += 'Zeitraum: ' + obj.Time.From + ' - ' + obj.Time.To + '\n';
    if (obj.Updated) result += 'Letztes Update: ' + obj.Updated + '\n';
    if (obj.Structure && obj.Structure.Head) result += '\nStatistik: [' + obj.Structure.Head.Code + '] ' + obj.Structure.Head.Content + '\n';
    const collect = (arr, depth) => {
      for (const v of (arr || [])) {
        result += '  '.repeat(depth) + '- [' + v.Code + '] ' + v.Content + ' (' + v.Type + ')\n';
        if (v.Structure) collect(v.Structure, depth + 1);
      }
    };
    if (obj.Structure && obj.Structure.Columns) { result += '\nSpalten-Variablen:\n'; collect(obj.Structure.Columns, 0); }
    if (obj.Structure && obj.Structure.Rows) { result += '\nZeilen-Variablen:\n'; for (const v of obj.Structure.Rows) result += '- [' + v.Code + '] ' + v.Content + ' (' + v.Type + ')\n'; }
    return [{ json: { result: trunc(result, 5000) } }];
  }

  if (action === 'genesis_get_table') {
    if (!input.name) return [{ json: { error: 'Parameter "name" ist erforderlich.' } }];
    const data = await genesisCall('data/table', {
      name: input.name,
      startyear: input.startyear || '',
      endyear: input.endyear || '',
      regionalvariable: input.regionalvariable || '',
      regionalkey: input.regionalkey || '',
      classifyingvariable1: input.classifyingvariable1 || '',
      classifyingkey1: input.classifyingkey1 || '',
      classifyingvariable2: input.classifyingvariable2 || '',
      classifyingkey2: input.classifyingkey2 || '',
      classifyingvariable3: input.classifyingvariable3 || '',
      classifyingkey3: input.classifyingkey3 || '',
      format: 'ffcsv',
      language: lang
    });
    const content = (data.Object && data.Object.Content) || '';
    let result = 'Daten Tabelle ' + input.name + ':\n\n```\n' + trunc(content, 4500) + '\n```';
    if (content.length > 4500) result += '\n\nFilter-Tipp: startyear/endyear (z.B. 2022/2024), regionalvariable+regionalkey (z.B. DLAND mit DG=Deutschland insgesamt), classifyingvariable1+classifyingkey1 fuer weitere Filter (z.B. NAT mit DEUTSCH=Deutsche).';
    return [{ json: { result } }];
  }

  if (action === 'genesis_get_timeseries') {
    if (!input.name) return [{ json: { error: 'Parameter "name" ist erforderlich.' } }];
    const data = await genesisCall('data/timeseries', {
      name: input.name,
      startyear: input.startyear || '',
      endyear: input.endyear || '',
      contents: input.contents || '',
      format: 'ffcsv',
      language: lang
    });
    const content = (data.Object && data.Object.Content) || '';
    const result = 'Zeitreihe ' + input.name + ':\n\n```\n' + trunc(content, 4500) + '\n```';
    return [{ json: { result } }];
  }

  if (action === 'genesis_quality_signs') {
    const data = await genesisCall('catalogue/qualitysigns', { language: lang });
    const list = data.List || [];
    let result = 'GENESIS Qualitaets-Sonderzeichen (Bedeutung in Datenzellen):\n\n';
    for (const it of list) result += '- `' + it.Code + '` -> ' + it.Content + '\n';
    return [{ json: { result } }];
  }

  return [{ json: { error: 'Unknown action: "' + action + '". Available: genesis_search, genesis_list_tables, genesis_list_statistics, genesis_list_variables, genesis_list_values, genesis_table_metadata, genesis_get_table, genesis_get_timeseries, genesis_quality_signs.' } }];
} catch (e) {
  return [{ json: { error: 'GENESIS-Aufruf fehlgeschlagen: ' + e.message } }];
}
